_PROCESS_PRIORITIES = ("low", "below_normal", "normal", "above_normal", "high")


def _set_process_priority(pid: int, process_priority: str) -> None:
    """Best-effort attempt to set the CPU priority of a process. Any
    failure is silently ignored since priority control is a resource
    optimization, not something the edit operation depends on.
    """
    if process_priority not in _PROCESS_PRIORITIES:
        return

    try:
        if WIN:
            import ctypes

            priority_classes = {
                "low": 0x00000040,  # IDLE_PRIORITY_CLASS
                "below_normal": 0x00004000,  # BELOW_NORMAL_PRIORITY_CLASS
                "normal": 0x00000020,  # NORMAL_PRIORITY_CLASS
                "above_normal": 0x00008000,  # ABOVE_NORMAL_PRIORITY_CLASS
                "high": 0x00000080,  # HIGH_PRIORITY_CLASS
            }
            handle = ctypes.windll.kernel32.OpenProcess(  # type: ignore[attr-defined]
                0x0200 | 0x0400, False, pid
            )
            if handle:
                try:
                    ctypes.windll.kernel32.SetPriorityClass(  # type: ignore[attr-defined]
                        handle, priority_classes[process_priority]
                    )
                finally:
                    ctypes.windll.kernel32.CloseHandle(handle)  # type: ignore[attr-defined]
        else:
            niceness = {
                "low": 10,
                "below_normal": 5,
                "normal": 0,
                "above_normal": -5,
                "high": -10,
            }
            os.setpriority(os.PRIO_PROCESS, pid, niceness[process_priority])
    except Exception:
        pass


